InvokeScript:
      if (-not (Get-ComputerRestorePoint)) {
          Enable-ComputerRestore -Drive $Env:SystemDrive
      }

      Checkpoint-Computer -Description "System Restore Point created by WinUtil" -RestorePointType MODIFY_SETTINGS
      Write-Host "System Restore Point Created Successfully" -ForegroundColor Green

      $RazerPath = "C:\Windows\Installer\Razer"

      if (Test-Path $RazerPath) {
        Remove-Item $RazerPath\* -Recurse -Force
      } else {
        New-Item -Path $RazerPath -ItemType Directory
      }

      icacls $RazerPath /deny "Everyone:(W)"

$path = 'HKCU:\Software\Microsoft\DirectX\UserGpuPreferences'
$name = 'DirectXUserGlobalSettings'
$current = Get-ItemProperty -Path $path -Name $name -ErrorAction SilentlyContinue
if ($current) {
  $val = $current.$name
  if ($val -match 'SwapEffectUpgradeEnable=') {
    $val = $val -replace 'SwapEffectUpgradeEnable=\d', 'SwapEffectUpgradeEnable=1'
  } else {
    $val = ($val.TrimEnd(';')) + ';SwapEffectUpgradeEnable=1'
  }
  Set-ItemProperty -Path $path -Name $name -Value $val
} else {
  New-Item -Path $path -Force | Out-Null
  Set-ItemProperty -Path $path -Name $name -Type String -Value 'SwapEffectUpgradeEnable=1'
}

UndoScript:
$regPath = 'HKLM:\SOFTWARE\Microsoft\Windows Photo Viewer\Capabilities\FileAssociations'
if (Test-Path $regPath) { Remove-Item -Path $regPath -Recurse -Force }
Write-Host "Windows Photo Viewer file associations removed."
